import React, { useState } from 'react';

function QuestionForm({ onSubmit, postulanteId, entrevistadorId }) {
  const [answers, setAnswers] = useState(Array(8).fill(''));
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const questions = [
    "Cuéntame un poco sobre ti.",
    "¿Por qué te interesa este puesto de desarrollador?",
    "¿Cuál consideras que ha sido tu mayor logro profesional?",
    "¿Cómo manejas situaciones de presión en el trabajo?",
    "¿Prefieres trabajar solo o en equipo? ¿Por qué?",
    "¿Dónde te ves profesionalmente dentro de 5 años?",
    "¿Por qué deberíamos contratarte para este puesto?",
    "¿Tienes experiencia previa relacionada con este tipo de trabajo?"
  ];

  const handleInputChange = (index, value) => {
    const newAnswers = [...answers];
    newAnswers[index] = value;
    setAnswers(newAnswers);
  };

  const enviarAlBackend = async () => {
    const respuestasEvaluadas = questions.map((q, i) => ({
      pregunta_id: i + 1,
      texto: answers[i] || "",
      evaluacion_automatica: "",
      puntaje_manual: 0,
      comentario_manual: ""
    }));

    const datos = {
      postulante_id: postulanteId,
      entrevistador_id: entrevistadorId,
      respuestas: respuestasEvaluadas
    };

    try {
      const response = await fetch("http://localhost/sistema-entrevistas/backend/api/guardar_respuesta.php", {
        method: "POST",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify(datos)
      });

      const result = await response.json();

      if (result.status === "ok") {
        alert("✅ Evaluación automática realizada por Jarvis y guardada.");
        onSubmit("Evaluación realizada por Jarvis.", answers);
      } else {
        alert("⚠️ Error al guardar la evaluación.");
      }
    } catch (err) {
      console.error("❌ Error al conectar con el backend:", err);
      alert("❌ Error al conectar con el backend.");
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    if (answers.some(answer => answer.trim() === '')) {
      setError('Por favor, responde todas las preguntas.');
      setLoading(false);
      return;
    }

    await enviarAlBackend();
    setLoading(false);
  };

  return (
    <form onSubmit={handleSubmit}>
      {questions.map((question, i) => (
        <div key={i} style={{ marginBottom: '10px' }}>
          <label htmlFor={`answer-${i}`}>{question}</label><br />
          <textarea
            id={`answer-${i}`}
            rows={3}
            style={{ width: '100%', padding: '8px' }}
            onChange={(e) => handleInputChange(i, e.target.value)}
            value={answers[i]}
            required
            disabled={loading}
          />
        </div>
      ))}

      <button type="submit" disabled={loading} style={{ padding: '10px 20px' }}>
        {loading ? 'Evaluando con Jarvis...' : 'Evaluar con Jarvis'}
      </button>

      {error && <p style={{ color: 'red' }}>{error}</p>}
    </form>
  );
}

export default QuestionForm;
